// Get raw input
const input = $input.first().json;

// Try to get data from different places
let matched_volunteers = [];
let event = {};

// Check if data is in body string
if (input.body && typeof input.body === 'string') {
  try {
    const parsed = JSON.parse(input.body);
    matched_volunteers = parsed.matched_volunteers || [];
    event = parsed.event || {};
  } catch(e) {}
}

// Check if data is directly in input
if (matched_volunteers.length === 0 && input.matched_volunteers) {
  matched_volunteers = input.matched_volunteers || [];
  event = input.event || {};
}

// Check if data is in nested body object
if (matched_volunteers.length === 0 && input.body && typeof input.body === 'object') {
  matched_volunteers = input.body.matched_volunteers || [];
  event = input.body.event || {};
}

// Return hardcoded test if still empty (for debugging)
if (matched_volunteers.length === 0) {
  return [{
    json: {
      debug: true,
      raw_input: JSON.stringify(input).substring(0, 500),
      volunteer_name: 'Test Volunteer',
      volunteer_email: 'shreyasgn11@outlook.com',
      volunteer_id: 'VOL_TEST',
      event_id: 'EVT_TEST',
      event_name: 'Test Event',
      event_date: '2026-03-20',
      event_time: '09:00',
      event_location: 'BIT Bengaluru',
      slots_total: 5
    }
  }];
}

// Return real volunteer data
return matched_volunteers.map(v => ({
  json: {
    volunteer_name: v.name,
    volunteer_email: v.email,
    volunteer_id: v.volunteer_id,
    event_id: event.event_id,
    event_name: event.name,
    event_date: event.date,
    event_time: event.time,
    event_location: event.location,
    slots_total: event.slots_total
  }
}));
